    BigInt(0),                                       // feedbackIndex: index of the feedback to respond to
    responseUri,                                     // uri: Arweave link to response details
    responseHash,                                    // hash: keccak256 of the response JSON
  ],
});

await sendGaslessContractCall(
  WALLET_ID,
